def main():
    deadline = time.time() + BUDGET_MIN * 60
    queue = sorted(TOPICS, key=_seo_score, reverse=True)
    print(f"=== WAVE 5 PREFLIGHT budget={BUDGET_MIN}m topics={len(queue)} workers={MAX_WORKERS} ===", flush=True)
    if not has_credential("OPENAI_API_KEY") or not ffmpeg_available():
        raise SystemExit("missing openai or ffmpeg")
    batch_t0 = time.perf_counter(); runs=[]; next_index=700; i=0
    while i < len(queue):
        if deadline - time.time() <= 30:
            print("=== WAVE 5 TIME BUDGET DONE ===", flush=True); break
        wave=[]
        while len(wave) < MAX_WORKERS and i < len(queue):
            wave.append((queue[i], next_index)); i += 1; next_index += 1
        with ThreadPoolExecutor(max_workers=MAX_WORKERS) as pool:
            futs={pool.submit(run_one, t, idx, len(queue)):(t,idx) for t,idx in wave}
            for fut in as_completed(futs):
                try: runs.append(fut.result())
                except Exception as exc:
                    t,idx=futs[fut]
                    runs.append({"run_index":idx,"topic":t["title"],"asset_id":t["asset_id"],"success":False,"production_error":str(exc),"cost":{"estimated_cost_usd":0}})
        live={"wave":5,"updated_at":datetime.now(timezone.utc).isoformat(),"seconds_remaining":max(0,int(deadline-time.time())),"completed":sum(1 for r in runs if r.get("success")),"attempted":len(runs),"queue_remaining":max(0,len(queue)-i)}
        (REPORT_DIR/"LIVE_BOARD_WAVE5.json").write_text(json.dumps(live,indent=2),encoding="utf-8")
    agg=aggregate(runs, round(time.perf_counter()-batch_t0,2), len(queue)); agg["wave"]=5
    path=REPORT_DIR/"SPRINT_WAVE5_REPORT.json"; path.write_text(json.dumps(agg,indent=2,default=str),encoding="utf-8")
    print("WAVE5 completed", agg["completed_ready_to_post"], "report", path, flush=True)
    return agg
if __name__ == "__main__":
    main()
